import { useEffect, useState } from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Login from "./Login";
import Signup from "./Signup";
import Admingifts from "./Admingifts";
import EditAdmin from "./EditGifts";
import AddTheme from "./AdminTheme";
import EditTheme from "./EditTheme";
import Orders from "./orders";
const express = require("express");

var cors = require('cors')

const app = express();

app.use(cors());

const { createProxyMiddleware } =require('http-proxy-middleware');

app.use('/api', createProxyMiddleware({ 

    target:'http://localhost:8080/', //original url

    changeOrigin:true, 

    //secure: false,

    onProxyRes:function (proxyRes, req, res) {

      proxyRes.headers['Access-Control-Allow-Origin'] = '*';

    }

}));
axios.get('http://localhost:5000/api/xxx', //proxy uri

{

   headers: {

      authorization: 'xxxxxxxxxx' ,

      'Content-Type':'application/json'

   } 

}).then(function (response) {

  
console.log(response);

});
app.listen(5000);
export default function App(){

    return(
    <div className="App">
    <BrowserRouter>
    <Routes>
        <Route path="/" element={<Signup/>}></Route>
        <Route path="/login" element={<Login/>}></Route>      
        <Route path = "/addGift" element={<Admingifts/>}> </Route> 
        <Route path = "/editGift" element={<EditAdmin/>}> </Route> 
        <Route path = "/addTheme" element={<AddTheme/>}> </Route> 
        <Route path = "/editTheme" element={<EditTheme/>}> </Route> 
        <Route path = "/orders" element={<Orders/>}> </Route>
    </Routes>
    </BrowserRouter>
    </div>)
}
